// src/nodes/inputNode.js
import { useState } from 'react';
import { Handle, Position } from 'reactflow';
import './node.css';

export const InputNode = ({ id, data }) => {
  const [currName, setCurrName] = useState(data?.inputName || `input_${id.slice(-4)}`);
  const [inputType, setInputType] = useState(data?.inputType || 'Text');

  const handleNameChange = (e) => {
    setCurrName(e.target.value);
    data.inputName = e.target.value;
    data.label = e.target.value;
  };

  const handleTypeChange = (e) => {
    setInputType(e.target.value);
    data.inputType = e.target.value;
  };

  return (
    <div className="vs-node">
      <div className="vs-node-header">{data?.label || "Input"}</div>
      <div className="vs-node-body">
        <label>
          Name:
          <input
            type="text"
            value={currName}
            onChange={handleNameChange}
            placeholder="Input name"
          />
        </label>
        <label>
          Type:
          <select value={inputType} onChange={handleTypeChange}>
            <option value="Text">Text</option>
            <option value="File">File</option>
          </select>
        </label>
      </div>
      <Handle type="source" position={Position.Right} id="value" />
    </div>
  );
};
